  "pc.consult.f1": { en: "5 AI-generated sessions, powered by RimSaju Engine", ko: "5회 AI 생성 세션 — RimSaju 엔진 기반", ja: "5回のAI生成セッション — RimSajuエンジン搭載", es: "5 sesiones generadas por AI, con RimSaju Engine", fr: "5 sessions générées par IA, propulsées par RimSaju Engine", pt: "5 sessões geradas por IA, com RimSaju Engine", "zh-TW": "5次AI生成諮詢，由RimSaju Engine驅動" },
  "pc.consult.f2": { en: "Just enter your birth details — no prior reading needed", ko: "생년월일만 입력 — 사전 리딩 불필요", ja: "生年月日を入力するだけ — 事前鑑定不要", es: "Solo ingresa tus datos de nacimiento — no necesitas lectura previa", fr: "Entre simplement tes données de naissance — pas besoin de lecture préalable", pt: "Apenas insira seus dados de nascimento — sem necessidade de leitura prévia", "zh-TW": "只需輸入出生資訊 — 不需要事先解讀" },
  "pc.consult.f3": { en: "Ask about career, love, timing, or any life question", ko: "직업, 연애, 시기 등 모든 질문 가능", ja: "仕事、恋愛、タイミングなど何でも質問", es: "Pregunta sobre carrera, amor, momentos clave, o cualquier pregunta de vida", fr: "Pose tes questions sur la carrière, l'amour, le timing ou tout sujet de vie", pt: "Pergunte sobre carreira, amor, momentos importantes ou qualquer questão de vida", "zh-TW": "詢問事業、感情、時機或任何人生問題" },
