  "reading.monthlyEnergy": { en: "Next 6 Months Energy Flow", ko: "향후 6개월 에너지 흐름", ja: "今後6ヶ月のエネルギー", es: "Flujo de energía — próximos 6 meses", fr: "Flux d'énergie — 6 prochains mois", pt: "Fluxo de energia — próximos 6 meses", "zh-TW": "未來6個月能量流" },
