  "reading.retryPersist": { en: "If this persists, your reading will be generated automatically on your next visit.", ko: "문제가 계속되면 다음 방문 시 자동으로 생성됩니다.", ja: "問題が続く場合、次回訪問時に自動生成されます。", es: "Si persiste, tu lectura se generará automáticamente en tu próxima visita.", fr: "Si cela persiste, ta lecture sera générée automatiquement à ta prochaine visite.", pt: "Se persistir, sua leitura será gerada automaticamente na sua próxima visita.", "zh-TW": "如果問題持續，你的解讀將於下次造訪時自動產生。" },
  "reading.unlockFull": { en: "Unlock Your Full Destiny", ko: "완전한 운명 열기", ja: "完全な運命を解放", es: "Desbloquea tu destino completo", fr: "Débloque ton destin complet", pt: "Desbloqueie seu destino completo", "zh-TW": "解鎖你的完整命運" },
  "reading.unlockDesc": { en: "10-year forecast · Career · Love · Health · Hidden Talent — all personalized to your chart.", ko: "10년 예측 · 직업 · 연애 · 건강 · 숨겨진 재능 — 모두 당신의 사주에 맞춤.", ja: "10年予測 · 仕事 · 恋愛 · 健康 · 隠れた才能 — すべてあなたの命式に合わせて。", es: "Pronóstico 10 años · Carrera · Amor · Salud · Talento oculto — todo personalizado a tu carta.", fr: "Prévisions 10 ans · Carrière · Amour · Santé · Talent caché — tout personnalisé à ta carte.", pt: "Previsão de 10 anos · Carreira · Amor · Saúde · Talento oculto — tudo personalizado para seu mapa.", "zh-TW": "10年預測 · 事業 · 愛情 · 健康 · 潛藏才華 — 全部依據你的命盤個人化。" },
