  "reading.oneTime": { en: "One-time payment. Yours forever.", ko: "1회 결제. 영원히 당신의 것.", ja: "一回払い。永遠にあなたのもの。", es: "Pago único. Tuya para siempre.", fr: "Paiement unique. À toi pour toujours.", pt: "Pagamento único. Sua para sempre.", "zh-TW": "一次付清。永遠屬於你。" },
  "reading.compatFree": { en: "Compatibility detailed analysis is already free for everyone!", ko: "궁합 상세 분석은 모든 분께 무료입니다!", ja: "相性の詳細分析はすべての方に無料です！", es: "¡El análisis detallado de compatibilidad ya es gratis para todos!", fr: "L'analyse détaillée de compatibilité est déjà gratuite pour tout le monde !", pt: "A análise detalhada de compatibilidade já é grátis para todos!", "zh-TW": "詳細合盤分析已對所有人免費！" },
