  "reading.saveShare": { en: "Save & share your reading", ko: "사주 저장 & 공유", ja: "鑑定を保存 & 共有", es: "Guardar y compartir tu lectura", fr: "Sauvegarder et partager ta lecture", pt: "Salvar e compartilhar sua leitura", "zh-TW": "儲存並分享你的命盤" },
  "reading.saveShareDesc": { en: "Sign in to save this reading to your dashboard, revisit anytime, and share with friends.", ko: "로그인하여 대시보드에 저장하고, 언제든 다시 보고, 친구와 공유하세요.", ja: "ログインしてダッシュボードに保存、いつでも閲覧、友人と共有。", es: "Inicia sesión para guardar esta lectura en tu panel, revisarla cuando quieras y compartir con amigos.", fr: "Connecte-toi pour sauvegarder cette lecture sur ton tableau de bord, la consulter à tout moment et la partager avec des amis.", pt: "Faça login para salvar esta leitura no seu painel, revisitar a qualquer momento e compartilhar com amigos.", "zh-TW": "登入以將此命盤儲存至儀表板，隨時查看並與朋友分享。" },
  "reading.free3s": { en: "Free — takes 3 seconds", ko: "무료 — 3초면 완료", ja: "無料 — 3秒で完了", es: "Gratis — tarda 3 segundos", fr: "Gratuit — prend 3 secondes", pt: "Grátis — leva 3 segundos", "zh-TW": "免費 — 只需3秒" },
