  "reading.verifyingDesc": { en: "Please wait — your reading will begin shortly.", ko: "잠시만 기다려주세요. 곧 리딩이 시작됩니다.", ja: "少々お待ちください。まもなく鑑定が始まります。", es: "Por favor espera — tu lectura comenzará en un momento.", fr: "Patiente s'il te plaît — ta lecture va commencer dans un instant.", pt: "Por favor aguarde — sua leitura começará em breve.", "zh-TW": "請稍候 — 你的解讀即將開始。" },
  "reading.generating": { en: "Generating your reading", ko: "사주 생성 중", ja: "四柱を生成中", es: "Generando tu lectura", fr: "Génération de ta lecture", pt: "Gerando sua leitura", "zh-TW": "正在生成你的命盤" },
  "reading.stayMsg": { en: "Please stay on this page — leaving may interrupt the reading.", ko: "이 페이지를 떠나지 마세요 — 해석이 중단될 수 있습니다.", ja: "このページを離れないでください — 解釈が中断される可能性があります。", es: "Por favor permanece en esta página — salir puede interrumpir la lectura.", fr: "Reste sur cette page s'il te plaît — quitter peut interrompre la lecture.", pt: "Por favor permaneça nesta página — sair pode interromper a leitura.", "zh-TW": "請停留在此頁面 — 離開可能中斷解讀。" },
